import UIKit
import Foundation
import URLSession

struct PromoLink {
    var baseURL: String = "https://myapp.com/promo"
    var queryItems: [URLQueryItem]
}

extension PromoLink {
    init?(from url: URL) {
        guard let components = URLComponents(url: url, resolvingAgainstBaseURL: false),
              let queryItems = components.queryItems else { return nil }

        self.init(queryItems: queryItems)
    }
}

struct PromoCode {
    var code: String?
    var discountPercentage: Double?

    mutating func applyToUserAccount() {
        // Apply the promo code and discount percentage to the user account
        // This method may include some database access or other operations specific to your app
    }
}

func processPromoLink(_ url: URL, completion: @escaping (PromoCode?) -> Void) {
    let promoLink = PromoLink(from: url)
    guard let promoLink = promoLink else { return }

    var promoCode = PromoCode()

    for item in promoLink.queryItems {
        switch item.name {
        case "code": promoCode.code = item.value
        case "discount": promoCode.discountPercentage = Double(item.value) / 100
        default: break
        }
    }

    completion(promoCode)
}

// Usage example in your AppDelegate's application(_:continue:restorationID:optionalUserInfo:) method
if let url = userInfo?[UIApplication.LaunchOptionsKey.url] as? URL {
    processPromoLink(url) { (promoCode) in
        if let promoCode = promoCode {
            promoCode.applyToUserAccount()
        }
    }
}